/* Markdown 段落 */
.konata-thinking-content p {
    margin: 10px 0;
    color: #c0c0c0;
}
.konata-thinking-content p:first-child {
    margin-top: 0;
}
.konata-thinking-content p:last-child {
    margin-bottom: 0;
}

/* 粗体 */
.konata-thinking-content strong {
    font-weight: 700;
    color: #ffffff;
    text-shadow: 0 0 10px rgba(255, 255, 255, 0.3);
}

/* 斜体 */
.konata-thinking-content em {
    font-style: italic;
    opacity: 0.9;
    color: #999999;
}

/* 行内代码 */
.konata-thinking-content code {
    background: rgba(50, 50, 50, 0.4);
    color: #cccccc;
    padding: 3px 8px;
